use crate::body::RigidBodySet;
use crate::collider::{Collider, ColliderHandle, ColliderSet, Shape};
use crate::contact::{ContactManifold, ContactPoint, PolyPolySatHint};
use crate::math::{Rot, Vec2};

/// Skip SAT axes built from nearly-degenerate polygon edges (duplicated verts, micro edges).
const POLY_EDGE_LEN2_MIN: f32 = 1e-12;

/// Epsilon below which we treat separation direction as **degenerate** (coincident centers or
/// ball center exactly on polygon edge / box feature). A fixed axis like `(1, 0)` breaks symmetry
/// poorly: equal-and-opposite impulses, SAT axis ties, and multi-body contact churn can leave pairs
/// effectively "stuck" and destabilize neighbors.
const COINCIDENT_SEP_EPS: f32 = 1e-5;

/// Stable unit vector from hashed positions — **order `(a, b)` matters** for pair convention.
fn stable_normal_for_coincident_positions(a: Vec2, b: Vec2) -> Vec2 {
    let bits_a = (a.x.to_bits() as u64) ^ ((a.y.to_bits() as u64) << 1);
    let bits_b = (b.x.to_bits() as u64) ^ ((b.y.to_bits() as u64) << 1);
    let mut h = bits_a
        .wrapping_mul(0x9e3779b97f4a7c15)
        .wrapping_add(bits_b.rotate_left(5))
        .wrapping_mul(0x9e3779b97f4a7c15);
    h ^= h >> 33;
    h = h.wrapping_mul(0xff51afd7ed558ccd);
    h ^= h >> 33;
    let t = ((h % 1_000_000) as f32) * (std::f32::consts::TAU / 1_000_000.0);
    Vec2::new(t.cos(), t.sin())
}

/// Normal from ball A toward other body B in world space; avoids vanishing `delta` at coincident COM.
fn ball_toward_other_normal(ball_pos: Vec2, other_pos: Vec2) -> Vec2 {
    let d = other_pos - ball_pos;
    let l2 = d.length_sq();
    if l2 > COINCIDENT_SEP_EPS * COINCIDENT_SEP_EPS {
        d * (1.0 / l2.sqrt())
    } else {
        stable_normal_for_coincident_positions(ball_pos, other_pos)
    }
}

/// Allow tiny negative overlap from float error before declaring separation — thin triangles
/// and other non-quad polygons can false-negative as tunneling if the test is too strict.
/// **Not** used for 4-vertex quads (cuboid–cuboid path) so stacks stay numerically crisp.
#[inline]
fn sat_overlap_is_separated_relaxed(overlap: f32, extent_a: f32, extent_b: f32) -> bool {
    let scale = (extent_a + extent_b).max(1e-6);
    let slop = (1e-5 * scale).max(1e-7);
    overlap < -slop
}

/// Overlap depth along `axis` (not normalized), or `None` if separated.
fn sat_overlap_on_axis(
    pos_a: Vec2,
    rot_a: Rot,
    verts_a: &[Vec2],
    pos_b: Vec2,
    rot_b: Rot,
    verts_b: &[Vec2],
    axis: Vec2,
    relaxed_sat_separation: bool,
) -> Option<f32> {
    let (min_a, max_a) = project_polygon(pos_a, rot_a, verts_a, axis);
    let (min_b, max_b) = project_polygon(pos_b, rot_b, verts_b, axis);
    let overlap = (max_a - min_b).min(max_b - min_a);
    let extent_a = max_a - min_a;
    let extent_b = max_b - min_b;
    let separated = if relaxed_sat_separation {
        sat_overlap_is_separated_relaxed(overlap, extent_a, extent_b)
    } else {
        overlap <= 0.0
    };
    if separated {
        None
    } else {
        Some(overlap)
    }
}

/// World-space outward-facing normal axis for a polygon edge, or `None` if the edge is degenerate.
#[inline]
fn polygon_edge_normal_axis(rot: Rot, vi: Vec2, vj: Vec2) -> Option<Vec2> {
    let e = rot.mul_vec(vj - vi);
    let len2 = e.length_sq();
    if len2 < POLY_EDGE_LEN2_MIN {
        return None;
    }
    Some(
        e.perp()
            .try_normalize()
            .unwrap_or(Vec2::new(1.0, 0.0)),
    )
}

/// Dispatch narrowphase collision detection for a pair of colliders.
#[allow(dead_code)] // Public wrapper; internal call sites use `detect_collision_with_hint`.
pub fn detect_collision(
    bodies: &RigidBodySet,
    colliders: &ColliderSet,
    handle_a: ColliderHandle,
    handle_b: ColliderHandle,
) -> Option<ContactManifold> {
    detect_collision_with_hint(bodies, colliders, handle_a, handle_b, None)
}

/// Like [`detect_collision`], with optional polygon–polygon SAT hysteresis from the contact tracker.
pub fn detect_collision_with_hint(
    bodies: &RigidBodySet,
    colliders: &ColliderSet,
    handle_a: ColliderHandle,
    handle_b: ColliderHandle,
    poly_hint: Option<PolyPolySatHint>,
) -> Option<ContactManifold> {
    let col_a = colliders.get(handle_a)?;
    let col_b = colliders.get(handle_b)?;

    // Skip sensor-sensor pairs
    if col_a.is_sensor() && col_b.is_sensor() {
        return None;
    }

    // Get world-space transforms
    let (pos_a, rot_a) = get_world_transform(bodies, col_a);
    let (pos_b, rot_b) = get_world_transform(bodies, col_b);

    // Dispatch based on shape types
    match (&col_a.shape, &col_b.shape) {
        (Shape::Ball { radius: ra }, Shape::Ball { radius: rb }) => {
            sat_ball_ball(pos_a, rot_a, *ra, pos_b, rot_b, *rb)
        }
        (Shape::Ball { radius }, Shape::Cuboid { hx, hy }) => {
            sat_ball_cuboid(pos_a, rot_a, *radius, pos_b, rot_b, *hx, *hy)
        }
        (Shape::Cuboid { hx, hy }, Shape::Ball { radius }) => {
            sat_ball_cuboid(pos_b, rot_b, *radius, pos_a, rot_a, *hx, *hy).map(|m| flip_manifold(m))
        }
        (Shape::Ball { radius }, Shape::Polygon { vertices }) => {
            sat_ball_polygon(pos_a, rot_a, *radius, pos_b, rot_b, vertices)
        }
        (Shape::Polygon { vertices }, Shape::Ball { radius }) => {
            sat_ball_polygon(pos_b, rot_b, *radius, pos_a, rot_a, vertices).map(|m| flip_manifold(m))
        }
        (Shape::Cuboid { hx: hxa, hy: hya }, Shape::Cuboid { hx: hxb, hy: hyb }) => {
            sat_cuboid_cuboid(
                pos_a, rot_a, *hxa, *hya, pos_b, rot_b, *hxb, *hyb, poly_hint,
            )
        }
        (Shape::Cuboid { hx, hy }, Shape::Polygon { vertices }) => {
            let verts_a = cuboid_vertices(*hx, *hy);
            sat_polygon_polygon(
                pos_a, rot_a, &verts_a, pos_b, rot_b, vertices, poly_hint,
            )
        }
        (Shape::Polygon { vertices }, Shape::Cuboid { hx, hy }) => {
            let verts_b = cuboid_vertices(*hx, *hy);
            sat_polygon_polygon(
                pos_a, rot_a, vertices, pos_b, rot_b, &verts_b, poly_hint,
            )
        }
        (Shape::Polygon { vertices: va }, Shape::Polygon { vertices: vb }) => {
            sat_polygon_polygon(pos_a, rot_a, va, pos_b, rot_b, vb, poly_hint)
        }
    }
}

/// World-space pose of the collider shape frame — same convention as SAT / `compute_collider_aabb`.
pub fn collider_world_transform(bodies: &RigidBodySet, collider: &Collider) -> (Vec2, Rot) {
    if let Some(parent_handle) = collider.parent {
        if let Some(body) = bodies.get(parent_handle) {
            let world_pos = body.pos + body.rot.mul_vec(collider.local_pos);
            let world_rot = body.rot.mul_rot(collider.local_rot);
            return (world_pos, world_rot);
        }
    }
    (collider.local_pos, collider.local_rot)
}

fn get_world_transform(bodies: &RigidBodySet, collider: &Collider) -> (Vec2, Rot) {
    collider_world_transform(bodies, collider)
}

fn flip_manifold(mut m: ContactManifold) -> ContactManifold {
    m.normal = -m.normal;
    m.poly_poly_sat = None;
    for cp in &mut m.contacts {
        std::mem::swap(&mut cp.local_a, &mut cp.local_b);
    }
    m
}

// ========== SAT: Ball-Ball ==========

pub fn sat_ball_ball(
    pos_a: Vec2,
    rot_a: Rot,
    radius_a: f32,
    pos_b: Vec2,
    rot_b: Rot,
    radius_b: f32,
) -> Option<ContactManifold> {
    let delta = pos_b - pos_a;
    let dist_sq = delta.length_sq();
    let total_r = radius_a + radius_b;

    if dist_sq >= total_r * total_r {
        return None;
    }

    let dist = dist_sq.sqrt();
    let normal = if dist > COINCIDENT_SEP_EPS {
        delta * (1.0 / dist)
    } else {
        ball_toward_other_normal(pos_a, pos_b)
    };

    let penetration = total_r - dist;
    let world_contact = pos_a + normal * (radius_a - penetration * 0.5);

    let wo_a = world_contact - pos_a;
    let wo_b = world_contact - pos_b;
    let local_a = rot_a.inv_mul_vec(wo_a);
    let local_b = rot_b.inv_mul_vec(wo_b);

    Some(ContactManifold::new(normal).with_point(local_a, local_b, penetration))
}

// ========== SAT: Ball-Cuboid ==========

pub fn sat_ball_cuboid(
    ball_pos: Vec2,
    ball_rot: Rot,
    ball_r: f32,
    box_pos: Vec2,
    box_rot: Rot,
    hx: f32,
    hy: f32,
) -> Option<ContactManifold> {
    // Negative half-extents make `x.clamp(-hx, hx)` violate `min <= max` (Rust panics).
    // WASM + fast-math paths surfaced this on mixed-settle seed 2147483629 (step 2).
    let hx = hx.abs();
    let hy = hy.abs();
    let ball_r = ball_r.max(0.0);

    // Transform ball center to box local space
    let local_ball = box_rot.inv_mul_vec(ball_pos - box_pos);

    // Find closest point on box to ball center (in local space)
    let closest = Vec2::new(local_ball.x.clamp(-hx, hx), local_ball.y.clamp(-hy, hy));

    let delta = local_ball - closest;
    let dist_sq = delta.length_sq();

    if dist_sq >= ball_r * ball_r {
        return None;
    }

    let dist = dist_sq.sqrt();
    // Normal points from A (ball) to B (box) so the solver pushes ball away from box
    let local_normal = if dist > COINCIDENT_SEP_EPS {
        -delta * (1.0 / dist)
    } else {
        // Ball center is inside the box — push out through nearest face.
        // Normal must still point from A (ball) toward B (box wall), i.e., toward exit.
        let dx = if local_ball.x >= 0.0 {
            hx - local_ball.x
        } else {
            hx + local_ball.x
        };
        let dy = if local_ball.y >= 0.0 {
            hy - local_ball.y
        } else {
            hy + local_ball.y
        };

        if dx < dy - 1e-12 {
            Vec2::new(if local_ball.x >= 0.0 { -1.0 } else { 1.0 }, 0.0)
        } else if dy < dx - 1e-12 {
            Vec2::new(0.0, if local_ball.y >= 0.0 { -1.0 } else { 1.0 })
        } else {
            // Square box / equal distances to faces: axis normals are symmetric — pick a stable
            // direction in **world** space then transform to box local.
            let world_n = stable_normal_for_coincident_positions(ball_pos, box_pos);
            box_rot.inv_mul_vec(world_n).try_normalize().unwrap_or(Vec2::new(1.0, 0.0))
        }
    };

    let penetration = if dist > COINCIDENT_SEP_EPS {
        ball_r - dist
    } else {
        // Inside: need to push ball center past the face + ball radius
        let dx = if local_ball.x >= 0.0 {
            hx - local_ball.x
        } else {
            hx + local_ball.x
        };
        let dy = if local_ball.y >= 0.0 {
            hy - local_ball.y
        } else {
            hy + local_ball.y
        };
        ball_r + dx.min(dy)
    };
    let world_normal = box_rot.mul_vec(local_normal);
    // Contact point on ball surface facing the box (normal from A→B, so contact is at ball + n*r)
    let world_contact = ball_pos + world_normal * (ball_r - penetration * 0.5);

    let wo_a = world_contact - ball_pos;
    let wo_b = world_contact - box_pos;
    let local_a = ball_rot.inv_mul_vec(wo_a);
    let local_b = box_rot.inv_mul_vec(wo_b);

    Some(ContactManifold::new(world_normal).with_point(local_a, local_b, penetration))
}

// ========== SAT: Ball-Polygon ==========

pub fn sat_ball_polygon(
    ball_pos: Vec2,
    ball_rot: Rot,
    ball_r: f32,
    poly_pos: Vec2,
    poly_rot: Rot,
    poly_verts: &[Vec2],
) -> Option<ContactManifold> {
    if poly_verts.is_empty() {
        return None;
    }

    // Transform ball center to polygon local space
    let local_ball = poly_rot.inv_mul_vec(ball_pos - poly_pos);

    // Find closest point on polygon edges
    let n = poly_verts.len();
    let mut min_dist_sq = f32::MAX;
    let mut closest_point = Vec2::zero();
    let mut inside = true;

    for i in 0..n {
        let j = (i + 1) % n;
        let edge = poly_verts[j] - poly_verts[i];
        let el2 = edge.length_sq();
        if el2 < POLY_EDGE_LEN2_MIN {
            continue;
        }
        let to_ball = local_ball - poly_verts[i];
        let t = to_ball.dot(edge) / el2;
        let t_clamped = t.clamp(0.0, 1.0);
        let point = poly_verts[i] + edge * t_clamped;
        let dist_sq = local_ball.distance_sq(point);

        if dist_sq < min_dist_sq {
            min_dist_sq = dist_sq;
            closest_point = point;
        }

        // Check winding direction to determine inside/outside
        if edge.perp().dot(to_ball) < 0.0 {
            inside = false;
        }
    }

    let dist = min_dist_sq.sqrt();

    if inside {
        // Ball center is inside polygon — push out through nearest edge.
        // Normal from A (ball) to B (polygon) = from ball center toward nearest edge.
        let penetration = ball_r + dist;
        let delta = closest_point - local_ball;
        let local_normal = if delta.length_sq() > COINCIDENT_SEP_EPS * COINCIDENT_SEP_EPS {
            delta * (1.0 / delta.length())
        } else {
            // Ball center is on or extremely close to an edge — pick a stable edge normal; break
            // ties by lowest edge index so symmetric triangles don't flip normals frame-to-frame.
            let mut best_edge_normal = Vec2::new(1.0, 0.0);
            let mut min_dot = f32::MAX;
            let mut best_i = usize::MAX;
            const TIE: f32 = 1e-7;
            for i in 0..n {
                let j = (i + 1) % n;
                let edge = poly_verts[j] - poly_verts[i];
                if edge.length_sq() < POLY_EDGE_LEN2_MIN {
                    continue;
                }
                let edge_normal = edge.perp().normalize();
                let to_center = local_ball - poly_verts[i];
                let d = edge_normal.dot(to_center);
                let ad = d.abs();
                if ad < min_dot - TIE || ((ad - min_dot).abs() <= TIE && (best_i == usize::MAX || i < best_i))
                {
                    min_dot = ad;
                    best_i = i;
                    best_edge_normal = if d >= 0.0 { edge_normal } else { -edge_normal };
                }
            }
            if best_i != usize::MAX {
                best_edge_normal
            } else {
                let w = ball_toward_other_normal(ball_pos, poly_pos);
                poly_rot
                    .inv_mul_vec(w)
                    .try_normalize()
                    .unwrap_or(Vec2::new(1.0, 0.0))
            }
        };
        let world_normal = poly_rot.mul_vec(local_normal);
        let world_contact = ball_pos + world_normal * ball_r;
        let wo_a = world_contact - ball_pos;
        let wo_b = world_contact - poly_pos;
        let local_a = ball_rot.inv_mul_vec(wo_a);
        let local_b = poly_rot.inv_mul_vec(wo_b);
        Some(ContactManifold::new(world_normal).with_point(local_a, local_b, penetration))
    } else if dist < ball_r {
        let penetration = ball_r - dist;
        // Normal from A (ball) to B (polygon) = from ball center toward polygon edge
        let delta = closest_point - local_ball;
        let local_normal = if delta.length_sq() > COINCIDENT_SEP_EPS * COINCIDENT_SEP_EPS {
            delta * (1.0 / delta.length())
        } else {
            let w = ball_toward_other_normal(ball_pos, poly_pos);
            poly_rot
                .inv_mul_vec(w)
                .try_normalize()
                .unwrap_or(Vec2::new(1.0, 0.0))
        };
        let world_normal = poly_rot.mul_vec(local_normal);
        let world_contact = ball_pos + world_normal * (ball_r - penetration * 0.5);
        let wo_a = world_contact - ball_pos;
        let wo_b = world_contact - poly_pos;
        let local_a = ball_rot.inv_mul_vec(wo_a);
        let local_b = poly_rot.inv_mul_vec(wo_b);
        Some(ContactManifold::new(world_normal).with_point(local_a, local_b, penetration))
    } else {
        None
    }
}

// ========== SAT: Cuboid-Cuboid (Separating Axis Theorem) ==========

pub fn sat_cuboid_cuboid(
    pos_a: Vec2,
    rot_a: Rot,
    hxa: f32,
    hya: f32,
    pos_b: Vec2,
    rot_b: Rot,
    hxb: f32,
    hyb: f32,
    sat_hint: Option<PolyPolySatHint>,
) -> Option<ContactManifold> {
    let verts_a = cuboid_vertices(hxa, hya);
    let verts_b = cuboid_vertices(hxb, hyb);
    sat_polygon_polygon(
        pos_a, rot_a, &verts_a, pos_b, rot_b, &verts_b, sat_hint,
    )
}

// ========== SAT: Polygon-Polygon ==========

pub fn sat_polygon_polygon(
    pos_a: Vec2,
    rot_a: Rot,
    verts_a: &[Vec2],
    pos_b: Vec2,
    rot_b: Rot,
    verts_b: &[Vec2],
    sat_hint: Option<PolyPolySatHint>,
) -> Option<ContactManifold> {
    if verts_a.is_empty() || verts_b.is_empty() {
        return None;
    }

    let na = verts_a.len();
    let nb = verts_b.len();
    let relaxed_sat_separation = na != 4 || nb != 4;

    let sep = pos_b - pos_a;
    let sep_len = sep.length();
    let sep_n = if sep_len > 1e-8 {
        sep * (1.0 / sep_len)
    } else {
        stable_normal_for_coincident_positions(pos_a, pos_b)
    };

    let mut min_penetration = f32::MAX;
    let mut best_axis = Vec2::zero();
    let mut best_from_a = true;
    let mut best_align = -1.0f32;

    #[inline]
    fn consider_axis(
        overlap: f32,
        axis: Vec2,
        from_a: bool,
        min_pen: &mut f32,
        best_axis: &mut Vec2,
        best_from_a: &mut bool,
        best_align: &mut f32,
        sep_n: Vec2,
    ) {
        let align = axis.dot(sep_n).abs();
        // Slightly wider tie band reduces axis flipping when overlaps are nearly equal (corners).
        let eps = 1.2e-3 * (*min_pen).max(1e-4);
        if overlap < *min_pen - eps {
            *min_pen = overlap;
            *best_axis = axis;
            *best_from_a = from_a;
            *best_align = align;
        } else if (overlap - *min_pen).abs() <= eps && align > *best_align {
            *best_axis = axis;
            *best_from_a = from_a;
            *best_align = align;
        }
    }

    // Test axes from A
    for i in 0..na {
        let j = (i + 1) % na;
        let Some(axis) = polygon_edge_normal_axis(rot_a, verts_a[i], verts_a[j]) else {
            continue;
        };

        let (min_a, max_a) = project_polygon(pos_a, rot_a, verts_a, axis);
        let (min_b, max_b) = project_polygon(pos_b, rot_b, verts_b, axis);

        let overlap = (max_a - min_b).min(max_b - min_a);
        let extent_a = max_a - min_a;
        let extent_b = max_b - min_b;
        let separated = if relaxed_sat_separation {
            sat_overlap_is_separated_relaxed(overlap, extent_a, extent_b)
        } else {
            overlap <= 0.0
        };
        if separated {
            return None;
        }

        consider_axis(
            overlap,
            axis,
            true,
            &mut min_penetration,
            &mut best_axis,
            &mut best_from_a,
            &mut best_align,
            sep_n,
        );
    }

    // Test axes from B
    for i in 0..nb {
        let j = (i + 1) % nb;
        let Some(axis) = polygon_edge_normal_axis(rot_b, verts_b[i], verts_b[j]) else {
            continue;
        };

        let (min_a, max_a) = project_polygon(pos_a, rot_a, verts_a, axis);
        let (min_b, max_b) = project_polygon(pos_b, rot_b, verts_b, axis);

        let overlap = (max_a - min_b).min(max_b - min_a);
        let extent_a = max_a - min_a;
        let extent_b = max_b - min_b;
        let separated = if relaxed_sat_separation {
            sat_overlap_is_separated_relaxed(overlap, extent_a, extent_b)
        } else {
            overlap <= 0.0
        };
        if separated {
            return None;
        }

        consider_axis(
            overlap,
            axis,
            false,
            &mut min_penetration,
            &mut best_axis,
            &mut best_from_a,
            &mut best_align,
            sep_n,
        );
    }

    // SAT axis hysteresis: prefer last frame’s axis when it is still valid and within margin of optimal.
    let d = pos_b - pos_a;
    if let Some(h) = sat_hint {
        let mut axis_h = h.axis_from_a_to_b;
        let len2 = axis_h.length_sq();
        if len2 > 1e-20 {
            axis_h = axis_h * (1.0 / len2.sqrt());
            if d.dot(axis_h) < 0.0 {
                axis_h = -axis_h;
            }
            if let Some(ov_h) = sat_overlap_on_axis(
                pos_a,
                rot_a,
                verts_a,
                pos_b,
                rot_b,
                verts_b,
                axis_h,
                relaxed_sat_separation,
            ) {
                let margin = (min_penetration * 0.12).max(5e-6).min(0.015);
                if ov_h <= min_penetration + margin {
                    let flipped_cur = d.dot(best_axis) < 0.0;
                    let cur_oriented = if flipped_cur {
                        -best_axis
                    } else {
                        best_axis
                    };
                    let align = axis_h.dot(cur_oriented).abs();
                    if align >= 0.88 {
                        best_axis = axis_h;
                        min_penetration = ov_h;
                        best_from_a = h.use_first_shape_as_reference;
                    }
                }
            }
        }
    }

    if min_penetration >= f32::MAX * 0.5 || best_axis.length_sq() < 1e-20 {
        return None;
    }

    // Ensure normal points from A to B
    let flipped = d.dot(best_axis) < 0.0;
    if flipped {
        best_axis = -best_axis;
    }

    // Reference face should have outward normal aligned with best_axis.
    // If the normal was flipped, swap reference/incident to maintain consistency.
    let use_a_as_ref = if flipped { !best_from_a } else { best_from_a };

    // Find contact points via edge clipping
    let (ref_verts, ref_pos, ref_rot, inc_verts, inc_pos, inc_rot) = if use_a_as_ref {
        (verts_a, pos_a, rot_a, verts_b, pos_b, rot_b)
    } else {
        (verts_b, pos_b, rot_b, verts_a, pos_a, rot_a)
    };

    let contacts = if use_a_as_ref {
        compute_contact_points(
            ref_pos, ref_rot, ref_verts, inc_pos, inc_rot, inc_verts, best_axis,
        )
    } else {
        // When B is reference, the reference face's outward normal aligns with -best_axis.
        // Since compute_contact_points uses min_dot (inward normal least aligned with passed normal),
        // we need to pass -best_axis so it selects the face whose inward normal is least aligned
        // with -best_axis (= most aligned with best_axis = outward normal aligned with -best_axis).
        compute_contact_points(
            ref_pos, ref_rot, ref_verts, inc_pos, inc_rot, inc_verts, -best_axis,
        )
    };

    let mut manifold = ContactManifold::new(best_axis);
    for (la, lb, pen) in contacts {
        // compute_contact_points returns (ref_frame, inc_frame).
        // When ref=B, swap so manifold always stores (A_frame, B_frame).
        if use_a_as_ref {
            manifold = manifold.with_point(la, lb, pen);
        } else {
            manifold = manifold.with_point(lb, la, pen);
        }
    }

    if manifold.contacts.is_empty() {
        // Fallback: use deepest penetrating vertices from both polygons
        let mut deepest_a = 0;
        let mut deepest_pen_a = -f32::MAX;
        for (i, v) in verts_a.iter().enumerate() {
            let world_v = pos_a + rot_a.mul_vec(*v);
            let proj = world_v.dot(best_axis);
            let pen = project_polygon(pos_b, rot_b, verts_b, best_axis).1 - proj;
            if pen > deepest_pen_a {
                deepest_pen_a = pen;
                deepest_a = i;
            }
        }

        let mut deepest_b = 0;
        let mut deepest_pen_b = -f32::MAX;
        for (i, v) in verts_b.iter().enumerate() {
            let world_v = pos_b + rot_b.mul_vec(*v);
            let proj = world_v.dot(-best_axis);
            let pen = project_polygon(pos_a, rot_a, verts_a, -best_axis).1 - proj;
            if pen > deepest_pen_b {
                deepest_pen_b = pen;
                deepest_b = i;
            }
        }

        // Add deepest vertex from A
        let world_va = pos_a + rot_a.mul_vec(verts_a[deepest_a]);
        let local_a = verts_a[deepest_a];
        let local_b = rot_b.inv_mul_vec(world_va - pos_b);
        manifold = manifold.with_point(local_a, local_b, deepest_pen_a.max(0.0));

        // Add deepest vertex from B if it's a different contact
        if deepest_pen_b > 0.0 && verts_a.len() + verts_b.len() > 3 {
            let world_vb = pos_b + rot_b.mul_vec(verts_b[deepest_b]);
            let local_b2 = verts_b[deepest_b];
            let local_a2 = rot_a.inv_mul_vec(world_vb - pos_a);
            manifold = manifold.with_point(local_a2, local_b2, deepest_pen_b.max(0.0));
        }
    }

    // Cap per-point penetration by SAT depth; only lift near-zero clip depths (numerical loss).
    const GEOMETRIC_ZERO: f32 = 1e-7;
    let hi = min_penetration.max(1e-12);
    for c in &mut manifold.contacts {
        if c.penetration <= GEOMETRIC_ZERO {
            let lo = (min_penetration * 0.15).clamp(1e-12, hi);
            c.penetration = lo.min(hi);
        } else {
            c.penetration = c.penetration.min(hi);
        }
    }

    merge_coincident_polygon_contacts(
        pos_a,
        rot_a,
        pos_b,
        rot_b,
        &mut manifold,
        min_penetration,
    );

    manifold.poly_poly_sat = Some(PolyPolySatHint {
        axis_from_a_to_b: manifold.normal,
        mtd: min_penetration,
        use_first_shape_as_reference: use_a_as_ref,
    });

    Some(manifold)
}

/// When SAT + clipping returns two points at the same corner (numerical duplicates), the
/// block solver applies two normal constraints with opposing torque arms but the same
/// penetration bias — a classic source of angular “explosions”. Merge any contacts whose
/// anchor on body A is coincident in world space (within an epsilon derived from MTD).
fn merge_coincident_polygon_contacts(
    pos_a: Vec2,
    rot_a: Rot,
    pos_b: Vec2,
    rot_b: Rot,
    manifold: &mut ContactManifold,
    min_penetration: f32,
) {
    if manifold.contacts.len() < 2 {
        return;
    }

    let eps = (min_penetration * 0.35)
        .max(1e-5)
        .min(0.02);
    let eps_sq = eps * eps;

    loop {
        let mut did_merge = false;
        'pair: for i in 0..manifold.contacts.len() {
            for j in (i + 1)..manifold.contacts.len() {
                let ci = &manifold.contacts[i];
                let cj = &manifold.contacts[j];
                let wi_a = pos_a + rot_a.mul_vec(ci.local_a);
                let wj_a = pos_a + rot_a.mul_vec(cj.local_a);
                let wi_b = pos_b + rot_b.mul_vec(ci.local_b);
                let wj_b = pos_b + rot_b.mul_vec(cj.local_b);
                let mid_i = (wi_a + wi_b) * 0.5;
                let mid_j = (wj_a + wj_b) * 0.5;
                let merge_a = wi_a.distance_sq(wj_a) < eps_sq;
                let merge_b = wi_b.distance_sq(wj_b) < eps_sq;
                let merge_mid = mid_i.distance_sq(mid_j) < eps_sq;
                if merge_a || merge_b || merge_mid {
                    let ci = manifold.contacts[i].clone();
                    let cj = manifold.contacts[j].clone();
                    let pen = ci.penetration.max(cj.penetration);
                    let la = (ci.local_a + cj.local_a) * 0.5;
                    let lb = (ci.local_b + cj.local_b) * 0.5;
                    let is_new = ci.is_new || cj.is_new;
                    manifold.contacts.remove(j);
                    manifold.contacts[i] = ContactPoint {
                        local_a: la,
                        local_b: lb,
                        penetration: pen,
                        impulse_id: i as u32,
                        is_new,
                    };
                    did_merge = true;
                    break 'pair;
                }
            }
        }
        if !did_merge {
            break;
        }
    }

    for (k, c) in manifold.contacts.iter_mut().enumerate() {
        c.impulse_id = k as u32;
    }
}

fn project_polygon(pos: Vec2, rot: Rot, verts: &[Vec2], axis: Vec2) -> (f32, f32) {
    let mut min = f32::MAX;
    let mut max = f32::MIN;
    for v in verts {
        let world_v = pos + rot.mul_vec(*v);
        let proj = world_v.dot(axis);
        min = min.min(proj);
        max = max.max(proj);
    }
    (min, max)
}

fn cuboid_vertices(hx: f32, hy: f32) -> [Vec2; 4] {
    [
        Vec2::new(-hx, -hy),
        Vec2::new(hx, -hy),
        Vec2::new(hx, hy),
        Vec2::new(-hx, hy),
    ]
}

/// Compute contact points via reference/incident edge clipping
fn compute_contact_points(
    ref_pos: Vec2,
    ref_rot: Rot,
    ref_verts: &[Vec2],
    inc_pos: Vec2,
    inc_rot: Rot,
    inc_verts: &[Vec2],
    normal: Vec2,
) -> Vec<(Vec2, Vec2, f32)> {
    // Find the reference face (edge most aligned with normal).
    // edge.perp() gives the inward normal for CCW polygons, so we negate it
    // to get the outward normal, then find the one most aligned with the contact normal.
    let ref_normal = ref_rot.inv_mul_vec(normal);
    let mut ref_idx = 0;
    let mut min_dot = f32::MAX;
    let n = ref_verts.len();
    for i in 0..n {
        let j = (i + 1) % n;
        if (ref_verts[j] - ref_verts[i]).length_sq() < POLY_EDGE_LEN2_MIN {
            continue;
        }
        let edge = (ref_verts[j] - ref_verts[i])
            .perp()
            .try_normalize()
            .unwrap_or(Vec2::new(1.0, 0.0));
        let d = edge.dot(ref_normal);
        if d < min_dot {
            min_dot = d;
            ref_idx = i;
        }
    }

    // Find the incident face (edge most anti-aligned with normal).
    // Same logic: edge.perp() is inward, we want the one whose outward normal
    // is most anti-aligned with the contact normal (i.e., most aligned with -normal).
    let inc_normal = inc_rot.inv_mul_vec(-normal);
    let mut inc_idx = 0;
    let mut min_dot = f32::MAX;
    let m = inc_verts.len();
    for i in 0..m {
        let j = (i + 1) % m;
        if (inc_verts[j] - inc_verts[i]).length_sq() < POLY_EDGE_LEN2_MIN {
            continue;
        }
        let edge = (inc_verts[j] - inc_verts[i])
            .perp()
            .try_normalize()
            .unwrap_or(Vec2::new(1.0, 0.0));
        let d = edge.dot(inc_normal);
        if d < min_dot {
            min_dot = d;
            inc_idx = i;
        }
    }

    let ref_next = (ref_idx + 1) % n;
    let inc_next = (inc_idx + 1) % m;

    // Reference edge in world space
    let ref_v1 = ref_pos + ref_rot.mul_vec(ref_verts[ref_idx]);
    let ref_v2 = ref_pos + ref_rot.mul_vec(ref_verts[ref_next]);

    // Incident edge in world space
    let inc_v1 = inc_pos + inc_rot.mul_vec(inc_verts[inc_idx]);
    let inc_v2 = inc_pos + inc_rot.mul_vec(inc_verts[inc_next]);

    // Clip incident edge against reference edge side planes
    let ref_edge = (ref_v2 - ref_v1).normalize();
    let ref_tangent = ref_edge.perp();

    let mut clipped = vec![inc_v1, inc_v2];

    // Clip against left side plane
    let side1 = ref_v1.dot(-ref_edge);
    clip_line_segment(&mut clipped, -ref_edge, side1);

    // Clip against right side plane
    let side2 = ref_v2.dot(ref_edge);
    clip_line_segment(&mut clipped, ref_edge, side2);

    // Keep only points behind reference face (inside reference body).
    // ref_tangent is the inward normal of the reference face, so we want
    // points where point · ref_tangent > ref_offset (inside the body).
    // Equivalently, using -ref_tangent as the outward normal: dist_out <= 0 ↔ dist_in >= 0.
    let outward = -ref_tangent;
    let ref_offset_out = ref_v1.dot(outward);
    // Small tolerance so near-boundary points from clipping are not dropped (reduces empty manifolds).
    const FACE_EPS: f32 = 1e-5;

    let mut contacts = Vec::new();
    for point in &clipped {
        let dist = point.dot(outward) - ref_offset_out;
        if dist <= FACE_EPS {
            let penetration = (-dist).max(0.0);
            let local_a = ref_rot.inv_mul_vec(*point - ref_pos);
            let local_b = inc_rot.inv_mul_vec(*point - inc_pos);
            contacts.push((local_a, local_b, penetration));
        }
    }

    // If side clipping or the face test dropped everything (parallel edges, numerical noise),
    // use incident edge endpoints so the solver still gets a stable manifold.
    if contacts.is_empty() {
        for world_pt in [inc_v1, inc_v2] {
            let dist = world_pt.dot(outward) - ref_offset_out;
            if dist <= FACE_EPS {
                let penetration = (-dist).max(0.0);
                let local_a = ref_rot.inv_mul_vec(world_pt - ref_pos);
                let local_b = inc_rot.inv_mul_vec(world_pt - inc_pos);
                contacts.push((local_a, local_b, penetration));
            }
        }
    }

    // Limit to 2 contacts for 2D block solver
    if contacts.len() > 2 {
        contacts.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal));
        contacts.truncate(2);
    }

    contacts
}

fn clip_line_segment(points: &mut Vec<Vec2>, normal: Vec2, offset: f32) {
    if points.len() < 2 {
        return;
    }

    let d0 = points[0].dot(normal) - offset;
    let d1 = points[1].dot(normal) - offset;

    if d0 * d1 < 0.0 {
        // One point is on each side, compute intersection
        let t = d0 / (d0 - d1);
        let intersection = points[0] + (points[1] - points[0]) * t;

        if d0 < 0.0 {
            points[1] = intersection;
        } else {
            points[0] = intersection;
        }
    } else if d0 <= 0.0 && d1 <= 0.0 {
        // Both points are behind or on the clip plane, keep both
    } else {
        // Both points are in front, remove all
        points.clear();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_ball_ball_coincident_centers_manifold() {
        let m = sat_ball_ball(
            Vec2::new(2.0, -1.0),
            Rot::identity(),
            0.4,
            Vec2::new(2.0, -1.0),
            Rot::identity(),
            0.5,
        );
        assert!(m.is_some());
        let m = m.unwrap();
        let len = m.normal.length();
        assert!(
            (len - 1.0).abs() < 1e-3,
            "normal should be unit, got length {len}"
        );
        assert!(m.max_penetration() > 0.85);
    }

    #[test]
    fn test_polygon_polygon_coincident_centers() {
        let va = cuboid_vertices(0.5, 0.5);
        let vb = cuboid_vertices(0.5, 0.5);
        let m = sat_polygon_polygon(
            Vec2::new(1.0, 2.0),
            Rot::identity(),
            &va,
            Vec2::new(1.0, 2.0),
            Rot::identity(),
            &vb,
            None,
        );
        assert!(
            m.is_some(),
            "coincident OBB polygons should still produce a manifold (stable SAT axis)"
        );
    }

    #[test]
    fn test_ball_ball_overlap() {
        let m = sat_ball_ball(
            Vec2::new(0.0, 0.0),
            Rot::identity(),
            1.0,
            Vec2::new(1.5, 0.0),
            Rot::identity(),
            1.0,
        );
        assert!(m.is_some());
        let m = m.unwrap();
        assert!((m.max_penetration() - 0.5).abs() < 1e-5);
    }

    #[test]
    fn test_ball_ball_no_overlap() {
        let m = sat_ball_ball(
            Vec2::new(0.0, 0.0),
            Rot::identity(),
            1.0,
            Vec2::new(3.0, 0.0),
            Rot::identity(),
            1.0,
        );
        assert!(m.is_none());
    }

    #[test]
    fn test_ball_cuboid() {
        let m = sat_ball_cuboid(
            Vec2::new(0.0, 0.0),
            Rot::identity(),
            0.5,
            Vec2::new(0.8, 0.0),
            Rot::identity(),
            0.5,
            0.5,
        );
        assert!(m.is_some());
        let m = m.unwrap();
        assert!(m.max_penetration() > 0.0);
    }

    #[test]
    fn test_ball_cuboid_negative_half_extent_does_not_panic() {
        let m = sat_ball_cuboid(
            Vec2::new(0.0, 0.0),
            Rot::identity(),
            0.5,
            Vec2::new(0.8, 0.0),
            Rot::identity(),
            -0.5,
            0.5,
        );
        assert!(m.is_some());
    }

    #[test]
    fn test_cuboid_cuboid() {
        let m = sat_cuboid_cuboid(
            Vec2::new(0.0, 0.0),
            Rot::identity(),
            0.5,
            0.5,
            Vec2::new(0.8, 0.0),
            Rot::identity(),
            0.5,
            0.5,
            None,
        );
        assert!(m.is_some());
        let m = m.unwrap();
        assert!((m.max_penetration() - 0.2).abs() < 1e-5);
        assert!(!m.contacts.is_empty());
    }

    #[test]
    fn test_cuboid_cuboid_rotated_overlap_has_contacts() {
        let m = sat_cuboid_cuboid(
            Vec2::new(0.0, 0.0),
            Rot::from_angle(0.35),
            0.5,
            0.5,
            Vec2::new(0.85, 0.0),
            Rot::from_angle(-0.22),
            0.5,
            0.5,
            None,
        );
        assert!(m.is_some());
        let m = m.unwrap();
        assert!(
            !m.contacts.is_empty(),
            "manifold should have contacts for rotated OBB overlap"
        );
        assert!(m.max_penetration() > 1e-4);
        let n = (m.normal.x * m.normal.x + m.normal.y * m.normal.y).sqrt();
        assert!((n - 1.0).abs() < 1e-3);
    }

    #[test]
    fn test_cuboid_cuboid_corner_on_edge() {
        // Thin floor + small rotated box overlapping (corner/edge case).
        let m = sat_cuboid_cuboid(
            Vec2::new(0.0, 0.0),
            Rot::identity(),
            1.0,
            0.15,
            Vec2::new(0.4, 0.2),
            Rot::from_angle(std::f32::consts::FRAC_PI_4),
            0.2,
            0.2,
            None,
        );
        assert!(m.is_some());
        let m = m.unwrap();
        assert!(
            !m.contacts.is_empty(),
            "corner-on-edge should still yield contact points"
        );
    }

    #[test]
    fn test_cuboid_cuboid_no_overlap() {
        let m = sat_cuboid_cuboid(
            Vec2::new(0.0, 0.0),
            Rot::identity(),
            0.5,
            0.5,
            Vec2::new(5.0, 0.0),
            Rot::identity(),
            0.5,
            0.5,
            None,
        );
        assert!(m.is_none());
    }

    #[test]
    fn test_polygon_polygon() {
        let tri_a = vec![
            Vec2::new(-0.5, -0.5),
            Vec2::new(0.5, -0.5),
            Vec2::new(0.0, 0.5),
        ];
        let tri_b = vec![
            Vec2::new(-0.5, -0.5),
            Vec2::new(0.5, -0.5),
            Vec2::new(0.0, 0.5),
        ];

        let m = sat_polygon_polygon(
            Vec2::new(0.0, 0.0),
            Rot::identity(),
            &tri_a,
            Vec2::new(0.5, 0.0),
            Rot::identity(),
            &tri_b,
            None,
        );
        assert!(m.is_some());
    }
}
